APP_NAME = "JSON Wandler"

VAT_RATES = {
    "AT": 0.20,
    "BE": 0.21,
    "BG": 0.20,
    "CY": 0.19,
    "CZ": 0.21,
    "DE": 0.19,
    "DK": 0.25,
    "EE": 0.24,
    "ES": 0.21,
    "FI": 0.255,
    "FR": 0.20,
    "GR": 0.24,
    "HR": 0.25,
    "HU": 0.27,
    "IE": 0.23,
    "IT": 0.22,
    "LT": 0.21,
    "LU": 0.17,
    "LV": 0.21,
    "MT": 0.18,
    "NL": 0.21,
    "PL": 0.23,
    "PT": 0.23,
    "RO": 0.21,
    "SE": 0.25,
    "SI": 0.22,
    "SK": 0.23,
}


def get_vat_rate(country_code: str | None) -> float:
    code = (country_code or "DE").strip().upper()
    return VAT_RATES.get(code, 0.0)


def next_invoice_nr() -> str:
    year = datetime.now(timezone.utc).year
    if not supabase:
        return f"{year}00001"
    result = supabase.table("hub_invoices").select("id", count="exact").limit(1).execute()
    count = result.count or 0
    return f"{year}{(count + 1):05d}"


def _required_text(source: dict, key: str, label: str) -> str:
    value = str(source.get(key, "")).strip()
    if not value:
        raise ValueError(f"missing_{label}")
    return value


def generate_plain_token(nbytes: int = 32) -> str:
    return secrets.token_urlsafe(nbytes)


def hash_token(token: str) -> str:
    return hashlib.sha256(token.encode()).hexdigest()


def generate_license_key() -> str:
    hex_str = uuid.uuid4().hex.upper()
    return f"JW-{hex_str[:6]}-{hex_str[6:12]}-{hex_str[12:18]}"


def _money_eur(cents: int | None) -> str:
    value = (cents or 0) / 100
    return f"{value:,.2f} EUR".replace(",", "X").replace(".", ",").replace("X", ".")


def _pdf_escape(text: str) -> str:
    return (
        text.replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _render_simple_invoice_pdf(invoice: dict, package_label: str) -> bytes:
    invoice_nr = str(invoice.get("invoice_nr", "-"))
    invoice_date = datetime.now(timezone.utc).astimezone().strftime("%d.%m.%Y")
    company = str(invoice.get("company") or "").strip()
    first_name = str(invoice.get("first_name") or "").strip()
    last_name = str(invoice.get("last_name") or "").strip()
    recipient = company or f"{first_name} {last_name}".strip() or "-"

    street = str(invoice.get("street") or "-")
    zip_code = str(invoice.get("zip") or "-")
    city = str(invoice.get("city") or "-")
    country = str(invoice.get("country") or "DE").upper()
    vat_id = str(invoice.get("vat_id") or "").strip()

    net_cents = int(invoice.get("amount_net_cents") or 0)
    vat_cents = int(invoice.get("amount_vat_cents") or 0)
    gross_cents = int(invoice.get("amount_gross_cents") or 0)
    vat_rate = int(round(get_vat_rate(country) * 100))

    # Parse quantity from package_label (e.g. "transformations-5" → 5)
    try:
        qty = int(package_label.split("-")[-1])
    except (ValueError, IndexError):
        qty = 1
    qty = max(1, qty)
    unit_net_cents = round(net_cents / qty)
    qty_label = f"JSON Wandler - {qty} Transformation{'en' if qty != 1 else ''}"
    package_name = qty_label

    def text_cmd(x: float, y: float, value: str, size: int = 10, bold: bool = False) -> str:
        font = "F2" if bold else "F1"
        return f"BT /{font} {size} Tf 1 0 0 1 {x:.2f} {y:.2f} Tm ({_pdf_escape(value)}) Tj ET"

    def right_text_cmd(right_x: float, y: float, value: str, size: int = 10, bold: bool = False) -> str:
        approx_w = max(10.0, len(value) * size * 0.46)
        return text_cmd(max(45.0, right_x - approx_w), y, value, size=size, bold=bold)

    cmds: list[str] = []

    # Header
    cmds.append("0.14 0.23 0.54 rg")
    cmds.append(text_cmd(45, 805, "K&N EDV Konzepte GmbH", 12, True))
    cmds.append("0 0 0 rg")
    cmds.append(text_cmd(45, 790, "Flurweg 14, D-83646 Bad Toelz", 10))
    cmds.append(text_cmd(45, 777, "dkoetting@edvkonzepte.de", 10))
    cmds.append("0.75 0.75 0.75 RG")
    cmds.append("0.8 w")
    cmds.append("45 765 m 550 765 l S")

    # Recipient block
    y = 735
    cmds.append(text_cmd(45, y, recipient, 11, True)); y -= 15
    cmds.append(text_cmd(45, y, street, 10)); y -= 13
    cmds.append(text_cmd(45, y, f"{zip_code} {city}", 10)); y -= 13
    if country and country != "DE":
        cmds.append(text_cmd(45, y, country, 10)); y -= 13
    if vat_id:
        cmds.append(text_cmd(45, y, f"UST-ID / VAT ID: {vat_id}", 9)); y -= 12

    # Invoice info block
    info_x = 360
    cmds.append(text_cmd(info_x, 735, "Datum / Date", 9))
    cmds.append(right_text_cmd(550, 735, invoice_date, 10))
    cmds.append(text_cmd(info_x, 720, "Lieferdatum / Delivery date", 9))
    cmds.append(right_text_cmd(550, 720, invoice_date, 10))
    cmds.append(text_cmd(info_x, 705, "Seite / Page", 9))
    cmds.append(right_text_cmd(550, 705, "1", 10))
    cmds.append(text_cmd(info_x, 690, "Rechnung Nr. / Invoice No.", 9))
    cmds.append("0.14 0.23 0.54 rg")
    cmds.append(right_text_cmd(550, 690, invoice_nr, 12, True))
    cmds.append("0 0 0 rg")

    # Title
    cmds.append("0.14 0.23 0.54 rg")
    cmds.append(text_cmd(45, 650, f"Rechnung / Invoice {invoice_nr}", 16, True))
    cmds.append("0 0 0 rg")

    # Table header
    table_y = 615
    cmds.append("0.14 0.23 0.54 rg")
    cmds.append(f"45 {table_y - 8} 505 30 re f")
    cmds.append("1 1 1 rg")
    cmds.append(text_cmd(52, table_y + 8, "Nr.", 8, True))
    cmds.append(text_cmd(80, table_y + 8, "Beschreibung", 8, True))
    cmds.append(right_text_cmd(340, table_y + 8, "Anzahl", 8, True))
    cmds.append(right_text_cmd(415, table_y + 8, "Preis", 8, True))
    cmds.append(right_text_cmd(470, table_y + 8, "USt.", 8, True))
    cmds.append(right_text_cmd(540, table_y + 8, "Gesamtpreis", 8, True))
    cmds.append("0 0 0 rg")

    # Table row
    row_y = table_y - 28
    cmds.append(text_cmd(52, row_y, "1", 11))
    cmds.append(text_cmd(80, row_y, package_name, 11, True))
    cmds.append(text_cmd(80, row_y - 14, "Digitale Lizenz / Digital license", 9))
    cmds.append(right_text_cmd(340, row_y, str(qty), 11))
    cmds.append(right_text_cmd(415, row_y, _money_eur(unit_net_cents), 11))
    cmds.append(right_text_cmd(470, row_y, f"{vat_rate} %", 11))
    cmds.append(right_text_cmd(540, row_y, _money_eur(net_cents), 11))

    cmds.append("0.88 0.88 0.88 RG")
    cmds.append("0.8 w")
    cmds.append(f"45 {row_y - 22} m 550 {row_y - 22} l S")

    # Totals block
    totals_top = 450
    labels_x = 315
    values_right = 550

    cmds.append(text_cmd(labels_x, totals_top, "Summe Netto:", 11))
    cmds.append(text_cmd(labels_x, totals_top - 12, "Net amount:", 9))
    cmds.append(right_text_cmd(values_right, totals_top, _money_eur(net_cents), 11))

    cmds.append(text_cmd(labels_x, totals_top - 36, f"zzgl. {vat_rate} % USt.:", 11))
    cmds.append(text_cmd(labels_x, totals_top - 48, f"plus {vat_rate}% VAT:", 9))
    cmds.append(right_text_cmd(values_right, totals_top - 36, _money_eur(vat_cents), 11))

    cmds.append("0.14 0.23 0.54 RG")
    cmds.append("1.2 w")
    cmds.append(f"{labels_x} {totals_top - 58} m {values_right} {totals_top - 58} l S")
    cmds.append("0 0 0 rg")
    cmds.append("0.14 0.23 0.54 rg")
    cmds.append(text_cmd(labels_x, totals_top - 84, "Gesamtbetrag:", 15, True))
    cmds.append(text_cmd(labels_x, totals_top - 98, "Total amount:", 10))
    cmds.append(right_text_cmd(values_right, totals_top - 84, _money_eur(gross_cents), 15, True))
    cmds.append("0 0 0 rg")

    # Payment note
    cmds.append(text_cmd(45, 210, "Vielen Dank fuer Ihren Kauf. Die Zahlung wurde erfolgreich via Stripe verarbeitet.", 11))
    cmds.append(text_cmd(45, 193, "Thank you for your purchase. Payment has been successfully processed via Stripe.", 10))

    content = "\n".join(cmds).encode("latin-1", errors="replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595 842] /Resources << /Font << /F1 5 0 R /F2 6 0 R >> >> /Contents 4 0 R >>",
        (f"<< /Length {len(content)} >>\nstream\n".encode("ascii") + content + b"\nendstream"),
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >>",
    ]

    out = bytearray(b"%PDF-1.4\n%\xE2\xE3\xCF\xD3\n")
    offsets = [0]
    for idx, obj in enumerate(objects, start=1):
        offsets.append(len(out))
        out.extend(f"{idx} 0 obj\n".encode("ascii"))
        out.extend(obj)
        out.extend(b"\nendobj\n")

    xref_pos = len(out)
    out.extend(f"xref\n0 {len(objects) + 1}\n".encode("ascii"))
    out.extend(b"0000000000 65535 f \n")
    for off in offsets[1:]:
        out.extend(f"{off:010} 00000 n \n".encode("ascii"))
    out.extend(
        f"trailer\n<< /Size {len(objects) + 1} /Root 1 0 R >>\nstartxref\n{xref_pos}\n%%EOF\n".encode("ascii")
    )
    return bytes(out)

