@app.post("/api/create-checkout-session")
async def create_checkout_session(request: Request):
    """Create Stripe checkout with billing data + pending invoice."""
    if not stripe.api_key:
        return JSONResponse(status_code=500, content={"error": "stripe_not_configured"})
    if not supabase:
        return JSONResponse(status_code=500, content={"error": "db_not_configured"})

    try:
        body = await request.json()
    except Exception:
        return JSONResponse(status_code=400, content={"error": "invalid_request"})

    try:
        quantity = int(body.get("quantity", 1))
    except Exception:
        return JSONResponse(status_code=400, content={"error": "invalid_quantity"})

    quantity = max(1, min(999, quantity))

    billing = body.get("billing") or {}
    if not isinstance(billing, dict):
        return JSONResponse(status_code=400, content={"error": "invalid_billing"})

    try:
        billing_type = str(billing.get("type", "private")).strip().lower()
        if billing_type not in {"company", "private"}:
            billing_type = "private"

        company = str(billing.get("company", "")).strip() or None
        vat_id = str(billing.get("vatId", "")).strip() or None
        first_name = str(billing.get("firstName", "")).strip() or None
        last_name = str(billing.get("lastName", "")).strip() or None

        if billing_type == "company" and not company:
            raise ValueError("missing_company")
        if billing_type == "private":
            if not first_name:
                raise ValueError("missing_first_name")
            if not last_name:
                raise ValueError("missing_last_name")

        street = _required_text(billing, "street", "street")
        zip_code = _required_text(billing, "zip", "zip")
        city = _required_text(billing, "city", "city")
        country = str(billing.get("country", "DE")).strip().upper()[:6] or "DE"
        email = _required_text(billing, "email", "email").lower()
        phone = str(billing.get("phone", "")).strip() or None
    except ValueError as exc:
        return JSONResponse(status_code=400, content={"error": str(exc)})

    amount_net = quantity * TRANSFORMATION_PRICE_CENTS
    vat_rate = get_vat_rate(country)
    amount_vat = round(amount_net * vat_rate)
    amount_gross = amount_net + amount_vat
    package_id = f"transformations-{quantity}"

    invoice_nr = next_invoice_nr()

    invoice_insert = supabase.table("hub_invoices").insert({
        "invoice_nr": invoice_nr,
        "status": "pending_payment",
        "billing_type": billing_type,
        "company": company,
        "vat_id": vat_id,
        "first_name": first_name,
        "last_name": last_name,
        "street": street,
        "zip": zip_code,
        "city": city,
        "country": country,
        "email": email,
        "phone": phone,
        "package_id": package_id,
        "amount_net_cents": amount_net,
        "amount_vat_cents": amount_vat,
        "amount_gross_cents": amount_gross,
    }).execute()

    if not invoice_insert.data:
        return JSONResponse(status_code=500, content={"error": "invoice_create_failed"})

    invoice_id = invoice_insert.data[0]["id"]

    try:
        session = stripe.checkout.Session.create(
            mode="payment",
            payment_method_types=["card"],
            customer_email=email,
            line_items=[{
                "quantity": 1,
                "price_data": {
                    "currency": STRIPE_CURRENCY,
                    "unit_amount": amount_gross,
                    "product_data": {
                        "name": f"JSON Wandler - Transformationen ({quantity})",
                        "description": f"{quantity} Transformation{'en' if quantity != 1 else ''} - {TRANSFORMATION_PRICE_CENTS / 100:.2f} EUR netto",
                    },
                },
            }],
            success_url=f"{APP_URL}/activate?session_id={{CHECKOUT_SESSION_ID}}",
            cancel_url=f"{APP_URL}/?cancelled=true",
            metadata={
                "app_id": APP_ID,
                "package_id": package_id,
                "max_transformations": str(quantity),
                "invoice_id": invoice_id,
                "invoice_nr": invoice_nr,
            },
            invoice_creation={"enabled": True},
        )

        supabase.table("hub_invoices").update({
            "stripe_session_id": session.id,
        }).eq("id", invoice_id).execute()

        return {"url": session.url, "session_id": session.id}
    except Exception as exc:
        return JSONResponse(status_code=500, content={"error": "stripe_error", "detail": str(exc)})
@app.post("/api/webhook/stripe")
async def stripe_webhook(request: Request):
    """Stripe webhook: create registration/license/access token and send email."""
    payload = await request.body()
    sig_header = request.headers.get("stripe-signature", "")

    try:
        event = stripe.Webhook.construct_event(payload, sig_header, STRIPE_WEBHOOK_SECRET)
    except Exception:
        print("[json-wandler/webhook] invalid signature")
        return JSONResponse(status_code=400, content={"error": "Invalid signature"})

    if event["type"] != "checkout.session.completed":
        return {"received": True}

    raw_session = event["data"]["object"]
    if hasattr(raw_session, "to_dict_recursive"):
        session = raw_session.to_dict_recursive() or {}
    elif hasattr(raw_session, "to_dict"):
        session = raw_session.to_dict() or {}
    elif isinstance(raw_session, dict):
        session = raw_session
    else:
        session = {}

    # Stripe can send metadata as null on synthetic/fixture events.
    # Treat it defensively so webhook tests never crash with 500.
    raw_metadata = session.get("metadata")
    if hasattr(raw_metadata, "to_dict_recursive"):
        metadata = raw_metadata.to_dict_recursive() or {}
    elif hasattr(raw_metadata, "to_dict"):
        metadata = raw_metadata.to_dict() or {}
    elif isinstance(raw_metadata, dict):
        metadata = raw_metadata
    else:
        metadata = {}

    # Some forwarded/thin webhook payloads do not include Checkout metadata.
    # In that case, fetch the full session from Stripe before routing by app_id.
    if not metadata.get("app_id") and session.get("id"):
        try:
            fetched_session = stripe.checkout.Session.retrieve(session.get("id"))
            if hasattr(fetched_session, "to_dict_recursive"):
                fetched_session_data = fetched_session.to_dict_recursive() or {}
            elif hasattr(fetched_session, "to_dict"):
                fetched_session_data = fetched_session.to_dict() or {}
            elif isinstance(fetched_session, dict):
                fetched_session_data = fetched_session
            else:
                fetched_session_data = {}
            if fetched_session_data:
                session = fetched_session_data
                raw_metadata = session.get("metadata")
                if isinstance(raw_metadata, dict):
                    metadata = raw_metadata
                else:
                    metadata = {}
        except Exception:
            print(f"[json-wandler/webhook] session fetch failed for id={session.get('id')}")

    if metadata.get("app_id") != APP_ID:
        print(
            f"[json-wandler/webhook] ignored event: app_id={metadata.get('app_id')} "
            f"expected={APP_ID} session_id={session.get('id')}"
        )
        return {"received": True}

    try:
        max_transformations = int(metadata.get("max_transformations", "0") or "0")
    except (TypeError, ValueError):
        max_transformations = 0
    package_id = metadata.get("package_id", "")
    invoice_id = metadata.get("invoice_id", "")
    invoice_nr = metadata.get("invoice_nr", "")
    email = (session.get("customer_details", {}).get("email", "") or "").lower().strip()
    full_name = session.get("customer_details", {}).get("name", "")
    now_iso = datetime.now(timezone.utc).isoformat()
    stripe_invoice_url = ""
    stripe_invoice_pdf = ""
    stripe_invoice_ref = ""

    stripe_invoice_id = session.get("invoice")
    if stripe_invoice_id:
        stripe_invoice_ref = str(stripe_invoice_id)
        # Stripe may create invoice_pdf slightly after checkout completion.
        for _ in range(5):
            try:
                invoice_obj = stripe.Invoice.retrieve(stripe_invoice_id)
                if hasattr(invoice_obj, "to_dict_recursive"):
                    invoice_data = invoice_obj.to_dict_recursive() or {}
                elif hasattr(invoice_obj, "to_dict"):
                    invoice_data = invoice_obj.to_dict() or {}
                elif isinstance(invoice_obj, dict):
                    invoice_data = invoice_obj
                else:
                    invoice_data = {}
                stripe_invoice_url = invoice_data.get("hosted_invoice_url", "") or ""
                stripe_invoice_pdf = invoice_data.get("invoice_pdf", "") or ""
                if stripe_invoice_pdf:
                    break
            except Exception:
                stripe_invoice_url = ""
                stripe_invoice_pdf = ""
            await asyncio.sleep(0.7)

    if not supabase:
        print("[json-wandler/webhook] supabase not configured")
        return JSONResponse(status_code=500, content={"error": "db_not_configured"})

    invoice_row = None
    if invoice_id:
        supabase.table("hub_invoices").update({
            "status": "paid",
            "stripe_session_id": session.get("id", ""),
        }).eq("id", invoice_id).execute()
        try:
            invoice_query = supabase.table("hub_invoices").select("*").eq("id", invoice_id).limit(1).execute()
            if invoice_query.data:
                invoice_row = invoice_query.data[0]
                if not invoice_nr:
                    invoice_nr = str(invoice_row.get("invoice_nr") or "")
        except Exception:
            invoice_row = None

    if not email or max_transformations <= 0:
        print(
            f"[json-wandler/webhook] missing metadata: email={email!r} "
            f"max_transformations={max_transformations}"
        )
        return JSONResponse(status_code=400, content={"error": "missing_metadata"})

    # 1. Registration anlegen (oder bestehende bei Duplicate)
    registration = None
    try:
        result = supabase.table("hub_registrations").insert({
            "email": email,
            "email_normalized": email,
            "full_name": full_name or None,
            "app_id": APP_ID,
            "app_name": APP_NAME,
            "app_price_cents": session.get("amount_total", 0),
            "app_currency": "EUR",
            "status": "active",
        }).execute()
        if result.data:
            registration = result.data[0]
            print(f"[json-wandler/webhook] registration created id={registration.get('id')}")
    except Exception:
        # Duplicate insert or transient insert error: fallback to lookup below.
        print("[json-wandler/webhook] registration insert failed, trying lookup fallback")
        registration = None

    if not registration:
        existing = supabase.table("hub_registrations").select("id").eq(
            "email_normalized", email
        ).eq("app_id", APP_ID).execute()
        if existing.data:
            registration = existing.data[0]
    if not registration:
        print("[json-wandler/webhook] registration missing after insert+lookup")
        return JSONResponse(status_code=500, content={"error": "db_error"})

    reg_id = registration["id"]

    # 2. Lizenz anlegen (license_key + max_gpts als Transformations-Credits)
    license_key = generate_license_key()
    supabase.table("hub_licenses").insert({
        "registration_id": reg_id,
        "license_key": license_key,
        "max_gpts": max_transformations,  # Credits = max_gpts
        "max_projects": 0,
        "status": "active",
    }).execute()
    print(f"[json-wandler/webhook] license created reg_id={reg_id} max={max_transformations}")

    # 3. Aktivierungs-Token erstellen
    plain_token = generate_plain_token()
    token_hash = hash_token(plain_token)
    expires_at = datetime.now(timezone.utc) + timedelta(hours=TTL_HOURS)

    supabase.table("hub_access_links").insert({
        "registration_id": reg_id,
        "token_hash": token_hash,
        "expires_at": expires_at.isoformat(),
    }).execute()
    print(f"[json-wandler/webhook] access link created reg_id={reg_id}")

    # 4. Events loggen
    supabase.table("hub_access_events").insert([
        {
            "registration_id": reg_id,
            "event_type": "stripe_payment_completed",
            "metadata": {
                "stripe_session_id": session.get("id", ""),
                "app_id": APP_ID,
                "package_id": package_id,
                "max_transformations": max_transformations,
                "amount_total": session.get("amount_total", 0),
                "created_at": now_iso,
                "invoice_id": invoice_id,
                "invoice_nr": invoice_nr,
                "invoice_url": stripe_invoice_url,
            },
        },
        {
            "registration_id": reg_id,
            "event_type": "license_created",
            "metadata": {
                "license_key": license_key,
                "max_transformations": max_transformations,
            },
        },
    ]).execute()

    # 5. Aktivierungs-Mail senden (via Resend)
    if RESEND_API_KEY:
        try:
            import httpx
            name_str = f" {full_name}" if full_name else ""
            app_open_url = f"{APP_URL}/activate"
            activation_url = f"{APP_URL}/?token={plain_token}"
            attachments = []
            package_label = f"transformations-{max_transformations}"

            if stripe_invoice_pdf:
                try:
                    pdf_resp = httpx.get(stripe_invoice_pdf, timeout=15)
                    if pdf_resp.status_code == 200 and pdf_resp.content:
                        attachments.append({
                            "filename": f"Rechnung_{invoice_nr or stripe_invoice_ref or reg_id}_JSON-Transformer.pdf",
                            "content": base64.b64encode(pdf_resp.content).decode("ascii"),
                        })
                except Exception:
                    pass

            if (not attachments) and invoice_row:
                try:
                    invoice_pdf_bytes = _render_simple_invoice_pdf(invoice_row, package_label)
                    attachments.append({
                        "filename": f"Rechnung_{invoice_nr or reg_id}_JSON-Transformer.pdf",
                        "content": base64.b64encode(invoice_pdf_bytes).decode("ascii"),
                    })
                except Exception:
                    pass

            invoice_line = (
                "Rechnung als PDF im Anhang / Invoice PDF attached."
                if attachments else
                f'Rechnung / Invoice link: <a href="{stripe_invoice_url or stripe_invoice_pdf or "#"}">{stripe_invoice_url or stripe_invoice_pdf or "pending"}</a>'
            )

            httpx.post(
                "https://api.resend.com/emails",
                headers={
                    "Authorization": f"Bearer {RESEND_API_KEY}",
                    "Content-Type": "application/json",
                },
                json={
                    "from": RESEND_FROM_EMAIL,
                    "to": [email],
                    "cc": ["buchhaltung@edvkonzepte.de"],
                    "subject": "JSON Transformer - Aktivierungs-Token & Rechnung / Activation token & Invoice",
                    "attachments": attachments,
                    "html": f"""
                        <p>Vielen Dank fuer deinen Kauf! / Thank you for your purchase!</p>
                        <p>Hallo{name_str} / Hello{name_str},</p>

                        <p><strong>Schritt 1 / Step 1 - JSON Transformer:</strong></p>
                        <p><a href="{app_open_url}" style="font-weight:bold;">-&gt; JSON Transformer oeffnen / Open JSON Transformer</a></p>

                        <p><strong>Schritt 2 / Step 2 - Aktivierungs-Token / Activation token:</strong></p>
                        <p style="font-family:monospace;font-size:16px;background:#f3f4f6;padding:12px;border-radius:6px;">
                          {plain_token}
                        </p>
                        <p><a href="{activation_url}" style="font-weight:bold;">-&gt; Optional direkt aktivieren / Optional activate directly</a></p>

                        <hr style="margin:18px 0;border:none;border-top:1px solid #ddd;" />
                        <p style="margin:0;">
                          Produkt / Product: JSON Wandler &mdash; {max_transformations} Transformation{'en' if max_transformations != 1 else ''}<br/>
                          Rechnung / Invoice: {invoice_nr or "-"}<br/>
                          {invoice_line}<br/>
                          Fragen? / Questions? dkoetting@edvkonzepte.de
                        </p>
                        <p style="margin-top:10px;color:#6b7280;font-size:12px;">
                          License key: {license_key}<br/>
                          Token gueltig fuer {TTL_HOURS} Stunden / Token valid for {TTL_HOURS} hours.
                        </p>
                    """,
                },
                timeout=10,
            )
            print(f"[json-wandler/webhook] email sent to {email}")
        except Exception as e:
            print(f"[json-wandler/webhook] E-Mail fehlgeschlagen: {e}")

    return {"received": True}


@app.get("/api/validate-token")
async def validate_token(token: str = ""):
    """Validate token and return remaining credits/license info."""
    if not token or not supabase:
        return JSONResponse(status_code=400, content={"valid": False, "error": "No token"})

    token_hash = hash_token(token)

    # 1. Token in hub_access_links suchen
    link_result = supabase.table("hub_access_links").select(
        "id, used_at, expires_at, registration_id"
    ).eq("token_hash", token_hash).execute()

    if not link_result.data:
        return JSONResponse(status_code=404, content={"valid": False, "error": "invalid"})

    link = link_result.data[0]

    # 2. Abgelaufen?
    if datetime.fromisoformat(link["expires_at"].replace("Z", "+00:00")) < datetime.now(timezone.utc):
        return JSONResponse(content={"valid": False, "error": "expired"})

    # 3. App-ID prÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¼fen
    reg_result = supabase.table("hub_registrations").select(
        "id, app_id, email"
    ).eq("id", link["registration_id"]).single().execute()

    if not reg_result.data or reg_result.data["app_id"] != APP_ID:
        return JSONResponse(content={"valid": False, "error": "wrong_app"})

    # 4. Lizenz + Credits laden
    license_result = supabase.table("hub_licenses").select(
        "license_key, max_gpts, status"
    ).eq("registration_id", link["registration_id"]).eq("status", "active").execute()

    if not license_result.data:
        return JSONResponse(content={"valid": False, "error": "no_license"})

    lic = license_result.data[0]
    credits_total = lic["max_gpts"]

    # 5. Verbrauchte Credits zÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¤hlen (Events)
    used_result = supabase.table("hub_access_events").select(
        "id", count="exact"
    ).eq("registration_id", link["registration_id"]).eq(
        "event_type", "transformation_used"
    ).execute()

    credits_used = used_result.count if used_result.count else 0
    credits_remaining = max(0, credits_total - credits_used)

    return {
        "valid": credits_remaining > 0,
        "credits_remaining": credits_remaining,
        "credits_total": credits_total,
        "license_key": lic["license_key"],
        "email": reg_result.data.get("email", ""),
    }


@app.post("/api/use-credit")
async def use_credit(request: Request):
    """1 Credit verbrauchen = Event 'transformation_used' loggen."""
    body = await request.json()
    token = body.get("token", "")
    license_key = body.get("license_key", "")

    if not supabase:
        return JSONResponse(status_code=500, content={"error": "db_not_configured"})

    # Lizenz finden (via token oder license_key)
    reg_id = None

    if token:
        token_hash = hash_token(token)
        link_result = supabase.table("hub_access_links").select(
            "registration_id, expires_at"
        ).eq("token_hash", token_hash).execute()
        if link_result.data:
            link_row = link_result.data[0]
            expires_at = str(link_row.get("expires_at") or "")
            if expires_at:
                expires_dt = datetime.fromisoformat(expires_at.replace("Z", "+00:00"))
                if expires_dt < datetime.now(timezone.utc):
                    return JSONResponse(status_code=403, content={"error": "token_expired"})
            reg_id = link_row["registration_id"]

    elif license_key:
        lic_result = supabase.table("hub_licenses").select(
            "registration_id"
        ).eq("license_key", license_key).eq("status", "active").execute()
        if lic_result.data:
            reg_id = lic_result.data[0]["registration_id"]

    if not reg_id:
        return JSONResponse(status_code=404, content={"error": "invalid_token"})

    # Credits prÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Â ÃƒÂ¢Ã¢â€šÂ¬Ã¢â€žÂ¢ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬ÃƒÂ¢Ã¢â‚¬Å¾Ã‚Â¢ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¼fen
    lic_result = supabase.table("hub_licenses").select(
        "max_gpts"
    ).eq("registration_id", reg_id).eq("status", "active").execute()

    if not lic_result.data:
        return JSONResponse(status_code=404, content={"error": "no_license"})

    credits_total = lic_result.data[0]["max_gpts"]

    used_result = supabase.table("hub_access_events").select(
        "id", count="exact"
    ).eq("registration_id", reg_id).eq("event_type", "transformation_used").execute()

    credits_used = used_result.count if used_result.count else 0
    credits_remaining = credits_total - credits_used

    if credits_remaining <= 0:
        return JSONResponse(status_code=403, content={
            "error": "no_credits",
            "credits_remaining": 0,
            "credits_total": credits_total,
        })

    # Credit verbrauchen = Event loggen
    insert_result = supabase.table("hub_access_events").insert({
        "registration_id": reg_id,
        "event_type": "transformation_used",
        "metadata": {
            "used_at": datetime.now(timezone.utc).isoformat(),
            "credits_before": credits_remaining,
        },
    }).execute()

    if not insert_result.data:
        print(f"[use_credit] ERROR: event insert failed for reg_id={reg_id}")
        return JSONResponse(status_code=500, content={"error": "credit_log_failed"})

    return {
        "credits_remaining": credits_remaining - 1,
        "credits_total": credits_total,
    }

